/** Italian story copy when locale is `it`. Maintained alongside `story-beat-bodies-es.ts`. */
export const STORY_BEAT_BODIES_IT: Readonly<Record<string, string>> = {
  'beat-neolithic-monuments': 'Molto prima di qualsiasi documento scritto, le comunità neolitiche eressero monumenti di pietra in ciò che sarebbe stata la Normandia. I dolmen di Vauville, i megaliti presso Fontenay-le-Marmion e le sepolture a Cairon segnano la prima impronta umana su questo paesaggio — uno strato fondazionale che sta sotto tutto ciò che segue.',
  'beat-bronze-channel': 'Lo stagno della Cornovaglia, il rame della penisola iberica e l\'ambra del Baltico attraversarono la Manica durante l\'età del bronzo. La costa normanna fu un punto di passaggio naturale: gli stessi porti che più tardi avrebbero accolto le navi vichinghe avevano già servito mercanti per oltre un millennio.',
  'beat-iron-age-tribes': 'Calèti, Veliocassi, Unelli e Abrincati tracciarono territori che avrebbero perdurato come confini amministrativi sotto Roma e oltre. Rotomagus —futura Rouen— era già il nodo dominante della Senna. Gli oppida che eressero occupavano le stesse alture strategiche dove più tardi si sarebbero innalzati castelli normanni.',
  'beat-roman-bridge': 'Dopo la conquista di Cesare, i territori tribali divennero civitates romane. Le strade sostituirono i sentieri forestali, gli anfiteatri sorsero accanto agli oppida e Rotomagus crebbe fino a capitale provinciale. Gli stessi corridoi fluviali che avevano servito il commercio celtico trasportavano ora chiatte di grano romano, e gli stessi forti costieri avrebbero più tardi ospitato le difese della costa sassone mentre l\'imperio crollava.',
  'beat-neustria': 'Dopo la caduta di Roma, i Franchi divisero la Gallia in sottoregni. La Neustria —la parte occidentale— abbracciava il bacino della Senna, con Rouen e Parigi come assi. Questa geografia politica preparò il terreno: la Senna era già un corridoio di potere molto prima dell\'arrivo dei vichinghi.',
  'beat-carolingian-frontier': 'L\'impero di Carlo Magno assorbì la Neustria in un vasto stato franco. L\'emporio costiero di Quentovic collegava la Gallia al commercio del Mare del Nord, mentre Nantes ancorava la tesa marca bretone a ovest. Abbazie fiorenti fiancheggiavano la Senna, ma la scala dell\'impero mise in tensione la difesa della frontiera: una vulnerabilità che si rivelò fatale quando le flotte scandinave apparvero all\'orizzonte.',
  'beat-seine-corridor': 'Sotto i Carolingi, la bassa Senna univa il cuore reale intorno a Parigi alla costa della Manica via Rouen. Ricche abbazie come Jumièges costeggiavano il fiume. Quella concentrazione di potere politico, economico e monastico lungo un solo corso d\'acqua rendeva la regione straordinariamente ricca — e straordinariamente vulnerabile.',
  'beat-viking-raids': 'Dal 840, flotte nordiche entrarono nell\'estuario della Senna e risalirono il fiume con efficacia devastante. Rouen fu presa, Jumièges saccheggiata e, nel 885, una flotta enorme assediò Parigi stessa. Lo stato franco non riuscì a difendere il suo corridoio fluviale: un fallimento che rimodellerebbe la mappa politica della Francia settentrionale.',
  'beat-frankish-weakness': 'Le incursioni ripetute trasformarono la bassa Senna da cuore franco in frontiera contesa. I re carolingi, indeboliti dalle guerre civili e incapaci di fermare le scorrerie, finirono per negoziare. Nel 911 Carlo il Semplice cedette il territorio della bassa Senna al capo vichingo Rollone in cambio di un cuscinetto difensivo: il trattato di Saint-Clair-sur-Epte. Non fu un dono, ma il riconoscimento che il potere franco aveva già perso il controllo della regione.',
  'beat-normandy-formation': 'Ciò che emerse dal trattato non fu solo una colonia vichinga. Nei decenni successivi i coloni nordici assorbirono istituzioni, lingua e cristianesimo franchi, conservando un\'aristocrazia guerriera e una vocazione marittima. Rouen divenne capitale ducale; i corridoi di insediamento si estesero verso ovest. A metà del X secolo il territorio aveva un nome —Normandia— e un\'identità propria: né del tutto franco né scandinavo, ma qualcosa di nuovo forgiato nel crogiolo della bassa Senna.',
  'beat-1': 'La Normandia conta non come mito d\'origine isolato, ma come cerniera costiera e fluviale tra popolazioni dell\'entroterra, competenza marittima e sbocco verso l\'Atlantico.',
  'beat-2': 'La mappa deve presentare le traversate come corridoi storici, non come registri perfetti di una singola nave. Il movimento passava di solito per sistemi di porti, contratti e ripetute partenze.',
  'beat-3': 'Un numero relativamente piccolo di coloni, reclutato ripetutamente attraverso canali regionali, poté lasciare un\'impronta culturale duratura quando si concentrò in insediamenti coloniali chiave.',
  'beat-migration-origins': 'La Nuova Francia attirò coloni da tutta la Francia atlantica, ma alcune regioni contribuirono molto più di altre. Il nord-ovest francese (Normandia, Bretagna, Perche) fornì circa il 39% di tutti gli immigrati e il centro-ovest (Aunis, Saintonge, Poitou) un altro 19%. Per questo molti franco-canadesi scoprono oggi antenati normanni o quasi normanni: il reclutamento ripetuto da porti e parrocchie del nord-ovest, insieme a un piccolo gruppo fondatore coloniale, lasciò un segno sproporzionato nella genealogia. Le isole del Canale facevano parte dello stesso mondo culturale normanno, ma Saint Peter Port e altri porti isolani non furono punti documentati di imbarco di massa verso la colonia: le navi partirono soprattutto da porti continentali come Dieppe, Honfleur, La Rochelle e Saint-Malo. Apri l\'Esploratore delle migrazioni per confrontare le coorti, leggi la sezione sulle isole del Canale e attiva i corridoi di flusso per vedere le rotte principali rispetto ai legami illustrativi più leggeri con le isole.',
  'beat-4': 'La storia atlantica è più ampia della sola Normandia. Porti come La Rochelle e Saint-Malo alimentarono corridoi coloniali distinti ma collegati attraverso l\'oceano.',
  'nf-arc-origins': 'La Nuova Francia attirò coloni da tutta la costa atlantica francese. Normandia, Perche, Bretagna e il centro-ovest apportarono coorti distinte —fondatori, engagés, soldati e figure religiose— che passarono da una manciata di porti d\'imbarco continentali (Dieppe, Honfleur, La Rochelle, Saint-Malo). Le isole del Canale appartenevano a quel mondo normanno sul piano culturale e storico, ma non furono terminali di massa per i viaggi coloniali; le persone nate sulle isole, quando compaiono, si integrano di solito in categorie più ampie francesi o normanne nei registri. Gli alberi genealogici franco-canadesi odierni mettono in evidenza la Normandia perché quei canali erano densi e la popolazione fondatrice del San Lorenzo era piccola, non perché la colonia fosse solo normanna.',
  'nf-arc-atlantic-crossing': 'Le navi partivano da Dieppe, La Rochelle, Honfleur e Saint-Malo in primavera, attraversavano in sei-dodici settimane e trasportavano coloni, viveri e merci verso il Canada. La colonia del San Lorenzo fu la destinazione demografica principale di molti di quei viaggi; l\'Acadia dipese soprattutto da La Rochelle e Saint-Malo nello stesso sistema di porti continentali —non da porti isolani del Canale come terminali principali. Il viaggio di ritorno riportava pelli in Francia.',
  'nf-arc-settlement-corridor': 'L\'insediamento si concentrò lungo il San Lorenzo in una sottile fascia signorile da Québec passando per Trois-Rivières fino a Montréal. Quel corridoio fu la spina dorsale della Nuova Francia: amministrativa, commerciale e militare.',
  'nf-arc-great-lakes': 'Esploratori come Champlain, Brûlé e Radisson portarono la presenza francese fino ai Grandi Laghi. Forti, missioni e avamposti commerciali a Michilimackinac, Sault Ste. Marie e Detroit formarono i nodi di una vasta rete interna collegata a Montréal dalla rotta del fiume Ottawa.',
  'nf-arc-mississippi': 'Joliet e Marquette (1673) confermarono che il Mississippi fluiva verso sud. La Salle, nato a Rouen, discese l\'intero fiume fino al golfo del Messico nel 1682 e rivendicò il bacino come Louisiana. In un colpo solo, la Nuova Francia passò da colonia fluviale a impero continentale.',
  'nf-arc-peak': 'All\'apice, dopo la Grande pace di Montréal (1701), la Nuova Francia era la maggiore estensione territoriale europea rivendicata in Nord America —dal golfo del San Lorenzo ai Grandi Laghi e al golfo del Messico. Ma la popolazione del nucleo del corridoio del San Lorenzo non superò i 70.000 coloni.',
  'nf-arc-collapse': 'La guerra dei sette anni pose fine a tutto. Louisbourg cadde nel 1758, Québec nel 1759 sulle pianure d\'Abraham e Montréal si arrese nel 1760. Il trattato di Parigi (1763) cedette l\'intera Nuova Francia alla Gran Bretagna. Un sistema continentale costruito in 150 anni scomparve dalla mappa —ma non dalla memoria né dalla genealogia.',
  'gc-beat-couture-rouen': 'Guillaume Couture fu battezzato il 14 gennaio 1618 a Rouen, capitale normanna sulla bassa Senna —lo stesso corridoio fluviale che avrebbe poi alimentato reclute e artigiani verso il Canada atlantico.',
  'gc-beat-couture-atlantic': 'Verso il 1640 attraversò come donné gesuita —associato laico destinato alle missioni. La traversata dai porti normanni a Québec durava settimane e segnava il passaggio tra apprendistato europeo e sopravvivenza americana.',
  'gc-beat-couture-quebec': 'Québec era ancora una debole testa di ponte francese sul San Lorenzo. Come falegname e donné, Couture entrava in un mondo in cui le alleanze con le nazioni indigene non erano facoltative —erano condizione di esistenza.',
  'gc-beat-couture-huronia': 'Nel 1641 percorse il corridoio del fiume Ottawa verso le missioni wendat (uron). Lì apprese lingue e mestieri che lo avrebbero reso uno degli interpreti più efficaci della colonia.',
  'gc-beat-couture-captivity': 'Al ritorno con Isaac Jogues fu catturato da un gruppo mohawk, torturato e adottato. Divenne il primo laico francese a vivere con credibilità nei villaggi haudenosaunee —una conoscenza di cui la colonia avrebbe disperatamente bisogno.',
  'gc-beat-couture-diplomacy': 'Dopo il 1645 scortò aperture di pace e negoziò lungo il fiume. Sulla signoria di Lauzon deteneva una concessione a Pointe-Lévy —non come signore, ma come habitant di fronte a Québec, radicato nella terra.',
  'gc-beat-couture-long-sault': 'Si offrì volontario per la sortita di Dollard des Ormeaux verso l\'Ottawa. L\'assedio del Long Sault divenne uno dei racconti militari fondativi del Canada francese —e Couture vi fu come interprete e combattente.',
  'gc-beat-couture-north-legacy': 'Nel 1663 guidò canoe per il Saguenay fino al lago Mistassini, tra le più profonde incursioni francesi nel subartico. Morì nel 1701 a Québec; i suoi discendenti portano ancora la storia normanna e laurentiana in Nord America.',
  'neo-arc-first-farmers': 'Intorno al 5000 a.C., la rivoluzione neolitica raggiunse le valli fluviali e le pianure costiere di ciò che sarebbe stata la Normandia. Comunità agricole provenienti da sud e est portarono grano e orzo domesticati, bestiame e uno stile di vita radicalmente nuovo. Per la prima volta le persone si stabilirono in modo permanente —abbatterono foreste, coltivarono terre e levarono villaggi sulle stesse terrazze fluviali e pianure costiere basse che avrebbero ospitato tutte le civiltà successive. Il paesaggio cominciava a essere rivendicato, e i primi segni di quella rivendicazione si sarebbero innalzati in pietra.',
  'neo-arc-dolmens': 'Il dolmen di Vauville, sulla costa ventosa del Cotentin, è tra i monumenti megalitici più antichi della Normandia. I dolmen erano camere funerarie collettive —lastre enormi erette per custodire le ossa degli antenati della comunità. Non si nascondevano: sorgevano su promontori, colline e argini fluviali visibili da lontano. Erigere un dolmen significava dichiarare: apparteniamo a questa terra e i nostri morti la vegliano. Il dolmen di Vauville è qui da tremila anni prima che nascesse il primo guerriero celtico.',
  'neo-arc-fontenay-cluster': 'Nel calcare intorno al Caen moderno, un denso gruppo di monumenti megalitici segnò uno dei paesaggi rituali neolitici più importanti del nord Francia. Il complesso di Fontenay-le-Marmion —con i suoi tumuli allungati e camere funerarie— e il sito vicino di Cairon formarono una geografia sacra che organizzò vita e morte delle comunità agricole per secoli. Non erano tombe isolate ma centri cerimoniali interconnessi, collocati secondo linee di vista e percorsi stagionali. La pianura di Caen fu il cuore della Normandia neolitica.',
  'neo-arc-allees-couvertes': 'L\'allée couverte di Bretteville-sur-Laize è una galleria funeraria —un corridoio lungo e stretto coperto da lastre, pensato per accogliere generazioni di defunti. Questi corridoi furono tra le imprese architettoniche più ambiziose del Neolitico europeo: alcuni superavano i venti metri, con muri decorati da motivi scolpiti. Erano monumenti comunitari che affermavano l\'importanza della comunità —non dell\'individuo. Ogni generazione aggiungeva i propri morti al passaggio, sovrapponendo il presente al passato in un rituale che sarebbe durato mille anni.',
  'neo-arc-menhirs': 'I menhir —pietre erette— sono i monumenti neolitici più enigmatici. Il menhir di Dol, vicino al confine tra Bretagna e Normandia, si erge in terreno pianeggiante come una sentinella. Confini, osservazione astronomica o culto? Forse tutto insieme. Di certo furono collocati intenzionalmente: a incroci, crini e limiti territoriali. Furono i primi segni lasciati dall\'uomo in un paesaggio che conosceva solo alberi e fiumi. La loro logica anticipò ogni confine, ogni cippo e ogni torre di chiesa successive.',
  'neo-arc-passais': 'Non tutti i monumenti erano sulla costa. La Table du Diable a Passais, nel bocage del sud della Normandia, mostra che anche le comunità dell\'interno investirono nel rituale megalitico. Questo «tavolo del diavolo» —un architrave enorme su pilastri— segna una sepoltura lontana dal mare, in terreni coltivati ondulati che a malapena sarebbero cambiati in cinque millenni. La Normandia neolitica non fu solo un fenomeno costiero: si estese in ogni valle e radura forestale dove gli agricoltori poterono mettere radici.',
  'neo-arc-sacred-landscape': 'Nel complesso, i monumenti megalitici della Normandia rivelano un paesaggio organizzato deliberatamente dalle prime comunità agricole. Dolmen sulla costa del Cotentin, allées couvertes nella pianura di Caen, menhir su confini territoriali, complessi funerari in centri rituali: non erano pietre a caso ma una geografia connessa del sacro e del politico. Gli stessi siti scelti per i monumenti —promontori, guadi, margini d\'altopiano— sarebbero stati scelti di nuovo da capi celtici, ingegneri romani, re franchi e signori normanni. La prima mappa della Normandia fu tracciata in pietra.',
  'neo-arc-bronze-horizon': 'Intorno al 2000 a.C., il mondo neolitico cedeva il passo a qualcosa di nuovo. La metallurgia —prima rame, poi bronzo— si diffuse da est e sud. La grande era della costruzione megalitica finiva, ma i monumenti restavano, silenziosi e duraturi. Arrivarono altri popoli, nuove tecnologie trasformarono l\'economia e la Manica divenne una via per il commercio dello stagno. Eppure dolmen, menhir e allées couvertes che levarono i primi agricoltori della Normandia sono ancora in piedi —come oggi—: lo strato più antico di memoria umana inciso in un paesaggio che non avrebbe smesso di rimodellarsi.',
  'bac-arc-channel-highway': 'Molto prima di qualsiasi registro scritto, la Manica era una delle vie navigabili più trafficate d\'Europa. Dal 2000 a.C., la domanda di bronzo —lega di rame e stagno— trasformò lo stretto in un\'autostrada marittima. Lo stagno della Cornovaglia e il rame del continente dovevano attraversare la Manica, e la costa di ciò che sarebbe stata la Normandia stava proprio sulla rotta. Coracle e canoe trasportavano metalli preziosi, ambra e idee tra Britannia e continente. La Manica non era una barriera; era un ponte.',
  'bac-arc-cornwall-tin': 'La Cornovaglia era uno dei pochi luoghi in Europa dove lo stagno abbondava. Senza stagno non c\'era bronzo; senza bronzo non c\'erano armi, attrezzi né beni di prestigio che definissero l\'epoca. Lo stagno cornovico era la merce più ambita dell\'Europa occidentale, e chi controllava l\'esportazione aveva un peso enorme. Due rotte marittime principali portavano quello stagno a sud attraverso la Manica: una alla costa del Cotentin, l\'altra alle scogliere calcaree del Pays de Caux. Entrambe facevano della costa normanna un punto critico in una rete commerciale continentale.',
  'bac-arc-cotentin-landing': 'La penisola del Cotentin si protendeva nella Manica come un molo, offrendo la traversata più breve verso il sud-ovest della Britannia. Le sue calle riparate e i porti naturali erano uno sbarco ideale per le imbarcazioni che trasportavano stagno, rame e merci. Gli insediamenti si raggruppavano vicino alla costa, e antichi monumenti neolitici come il dolmen di Vauville dominavano ancora i promontori —testimoni muti di un paesaggio già plasmato da millenni di attività umana. Il Cotentin era l\'incontro tra mondo atlantico e continentale.',
  'bac-arc-tin-trade-peak': 'Intorno al 1500 a.C., il commercio per la Manica raggiunse il culmine. Due corridoi marittimi ben battuti univano la Cornovaglia alla costa normanna: una rotta occidentale al Cotentin e una orientale al Caux. Da quegli sbarchi le merci proseguivano verso l\'interno lungo fiumi e sentieri fino all\'estuario della Senna e oltre —verso il cuore della Gallia continentale. I manufatti in bronzo rinvenuti nel nord Francia portano la firma chimica dello stagno cornovico: non era uno scambio occasionale ma un sistema commerciale sostenuto e organizzato. La Manica era l\'autostrada del suo tempo.',
  'bac-arc-seine-estuary': 'L\'estuario della Senna era dove il mondo marittimo della Manica incontrava il mondo fluviale dell\'interno gallico. Le merci arrivate per mare —stagno, rame, ambra, sale— venivano qui trasbordate su imbarcazioni fluviali che risalivano verso ciò che un giorno sarebbe stata Parigi. Questo punto di trasbordo era l\'antenato di ogni porto che avrebbe occupato quel tratto di costa: la Rotomagus romana, la Rouen vichinga, i porti medievali della Senna. La geografia dell\'estuario —ampio, a marea, navigabile— lo faceva porta naturale, e ogni civiltà successiva lo avrebbe usato come tale.',
  'bac-arc-caux-coast': 'La rotta orientale della Manica portava lo stagno cornovico alla costa calcarea del Pays de Caux —le scogliere bianche a nord della Senna. Qui spiagge riparate tra capi offrivano punti di sbarco ai mercanti. La costa del Caux si collegava direttamente al territorio dei Calèti nell\'età del ferro, e i porti rivolti alla Manica avrebbero servito tutti i popoli marittimi, dai mercanti del bronzo ai pescatori normanni. La stessa geografia costiera che attirò i mercanti dello stagno attirò più tardi gli assalitori vichinghi in cerca della Senna.',
  'bac-arc-neolithic-memory': 'Sparsi nel paesaggio, i grandi monumenti neolitici —dolmen, menhir e allées couvertes— restavano in piedi durante l\'età del bronzo, già antichi. Il dolmen di Vauville nel Cotentin e il complesso megalitico di Fontenay-le-Marmion avevano migliaia di anni, eretti da comunità agricole il cui mondo era scomparso. Eppure i popoli del bronzo non li ignorarono: riutilizzarono camere funerarie, deposero offerte in antichi luoghi sacri e orientarono gli insediamenti rispetto a quei segnali ancestrali. Il paesaggio era stratificato, e perfino i nuovi arrivati costruivano sul passato degli altri.',
  'bac-arc-iron-horizon': 'Intorno all\'800 a.C., un nuovo metallo si diffuse in Europa: il ferro. Più economico e abbondante del bronzo, non richiedeva il commercio a lunga distanza dello stagno che aveva alimentato le reti della Manica. I grandi corridoi marittimi cominciarono a mutare, e le comunità costiere che vivevano come intermediarie del commercio dello stagno videro trasformarsi il loro mondo. Ma l\'eredità del bronzo perdurò: porti, rotte marittime, conoscenza delle traversate della Manica e schemi di insediamento costiero sopravvissero all\'età del ferro. Le tribù celtiche ereditarono un paesaggio già cartografato da secoli di commercio marittimo —e la Manica sarebbe rimasta una via, in attesa della prossima flotta.',
  'iag-arc-celtic-dawn': 'Dall\'800 a.C., popoli celtici dell\'età del ferro si diffusero nel nord della Gallia, trasformando il paesaggio con nuove tecnologie, strutture sociali e aristocrazie guerriere. La regione tra la Senna e la Manica —poi nota come Normandia— fu divisa tra tribù potenti di lingua gallica, culto alle divinità della natura e ricchezza fondata su agricoltura, metallurgia e commercio. Non era un angolo periferico: il corridoio della Senna e la costa della Manica la rendevano una delle regioni meglio collegate dell\'Europa preromana.',
  'iag-arc-veliocasses': 'I Veliocassi erano la tribù dominante della bassa valle della Senna. La loro capitale a Rotomagus (l\'odierna Rouen) controllava il punto in cui il fiume a marea incontrava la navigazione fluviale interna —un collo di bottiglia strategico che avrebbe deciso il destino della regione per due millenni. Il loro oppidum dominava le alture sul fiume, con castelli satellite come Duclair che vigilavano gli accessi. Dominare la Senna dava ai Veliocassi il controllo del commercio interno: stagno, sale, grano e schiavi attraversavano il loro territorio. Rotomagus era già città in tutto tranne che nel nome.',
  'iag-arc-caletes': 'A nord della Senna, i Calèti controllavano il Pays de Caux —l\'altopiano calcareo che precipita in scogliere bianche verso la Manica. Il loro territorio dava accesso a ricche zone di pesca e al commercio transmanico con la Britannia. Il loro insediamento principale presso l\'attuale Lillebonne (poi la romana Juliobona) sorgeva all\'incrocio di rotte terrestri e fluviali. I Calèti erano intermediari: tra i Veliocassi della Senna e il mondo marittimo oltre, traevano profitto da ogni scambio.',
  'iag-arc-western-tribes': 'A ovest della Senna, due tribù più piccole ma strategiche occupavano il Cotentin e la baia del Monte Saint-Michel. Gli Unelli, centrati su Cosedia (Coutances), dominavano le traversate verso la Britannia e parte della costa più contesa della Gallia. Gli Abrincati, intorno ad Abrincae (Avranches), vigilavano la porta tra Bretagna e mondo della Senna. Pur meno potenti dei Veliocassi, queste tribù occidentali controllavano i margini marittimi che collegavano l\'Atlantico celtico all\'interno gallico.',
  'iag-arc-seine-corridor': 'Molto prima di Roma, la Senna era già una grande arteria commerciale. Da Lutecia —l\'insediamento insulare dei Parisii— le merci scendevano lungo il fiume passando per i Veliocassi fino alla Manica e oltre. Stagno della Cornovaglia, ambra del Baltico, vino dal Mediterraneo: tutto passava per questo corridoio in mano celtica. Il fiume imponeva una logica al paesaggio che nessun mutamento politico avrebbe alterato. Ogni potere che controllasse la Senna —celtico, romano, franco, vichingo, normanno— avrebbe prosperato; chi la perdeva, sarebbe caduto.',
  'iag-arc-oppida': 'Nel III secolo a.C., le tribù galliche erigevano oppida —insediamenti fortificati in altura che servivano da capitali, mercati e rifugi. Non erano semplici forti: i maggiori ospitavano officine, granai, zecche e recinti sacri. L\'oppidum di Rotomagus dominava la Senna; Juliobona comandava il paese calcareo dei Calèti; Cosedia ancorava il Cotentin degli Unelli; Abrincae vigilava la baia. Quegli emplacements scelsero le stesse alture strategiche —meandri, promontori costieri, margini d\'altopiano— che avrebbero occupato poi le città romane, i palazzi franchi e i castelli normanni. La geografia tracciò la mappa prima che qualsiasi impero la disegnasse.',
  'iag-arc-resistance': 'Quando le legioni di Giulio Cesare irruppero nella Gallia negli anni 50 a.C., le tribù della Senna e del Cotentin resistettero. Viridovix, capo degli Unelli, sollevò una grande coalizione contro Roma nel 56 a.C., ma fu sconfitto da Sabino nella battaglia degli Unelli. I Veliocassi, intrappolati tra il potere romano e il proprio orgoglio, si sottomisero con minor violenza. Anche Calèti e Abrincati piegarono il ginocchio. La resistenza fu feroce ma frammentata: ogni tribù combatté sola e Roma le conquistò una a una. Il mondo celtico del nord della Gallia giungeva alla fine.',
  'iag-arc-eve-of-rome': 'Nel 52 a.C., la conquista di Cesare era completa. I territori tribali che avevano plasmato il nord della Gallia per secoli —i Veliocassi lungo la Senna, i Calèti sulla costa calcarea, gli Unelli nel Cotentin, gli Abrincati presso la baia— sarebbero stati ridisegnati come civitates romane. Ma i modelli profondi sopravvissero: il corridoio fluviale, le alture strategiche, le rotte costiere, i confini tribali che Roma solo rinominò. L\'età del ferro finiva, ma la geografia che aveva cartografato —e i luoghi che aveva scelto— avrebbero perdurato in tutte le epoche successive.',
  'rg-arc-caesars-conquest': 'Nel 52 a.C., Giulio Cesare completò la conquista della Gallia e incorporò le tribù celtiche del bacino della Senna nell\'impero romano. I Veliocassi a Rotomagus, i Calèti sulla costa della Manica e i vicini furono assorbiti dalla vasta macchina della Repubblica. Gli oppida celtici non furono distrutti ma riutilizzati: le loro fortezze in altura divennero nucleo di nuove città romane. La Senna, già antico corridoio commerciale, avrebbe ora servito un impero.',
  'rg-arc-civitates': 'Roma riorganizzò i territori celtici in civitates —distretti amministrativi che conservavano i confini tribali imponendo legge, fiscalità e urbanistica romani. I Veliocassi divennero la civitas di Rotomagus, i Calèti si concentrarono su Juliobona (Lillebonne), gli Unelli su Cosedia (Coutances) e gli Abrincati su Abrincae (Avranches). Ogni capitale civitas ricevette monumenti romani —fori, terme, templi— sovrapposti al paesaggio celtico più antico. La mappa tribale della Gallia si ridisegnava con inchiostro romano.',
  'rg-arc-rotomagus': 'Nel II secolo, Rotomagus (Rouen) era cresciuta da oppidum celtico a una delle città più importanti della Gallia romana. Come capitale della Lugdunensis Secunda, amministrava una vasta provincia dalla Senna alla penisola del Cotentin. La Rotomagus romana aveva foro, terme pubbliche, anfiteatro e porto fluviale che la univa all\'interno e alla Manica. La sua posizione strategica —dove le acque di marea incontrano il fiume— la faceva porta naturale tra il nord della Gallia e il mare, ruolo che non avrebbe mai abbandonato.',
  'rg-arc-seine-artery': 'Sotto Roma, la Senna divenne arteria commerciale gestita. Chiatte di grano portavano raccolti dall\'Île-de-France ai porti della Manica; vino, olio e ceramica risalivano dal Mediterraneo. Lutecia (Parigi) e Rotomagus (Rouen) erano i due grandi nodi di questa via d\'acqua, uniti da un corridoio di ville, fattorie e poste. Gli ingegneri romani migliorarono la navigabilità e i esattori imperiali assicurarono che ogni carico pagasse la sua parte. La prosperità di questo corridoio avrebbe risuonato in tutte le epoche future.',
  'rg-arc-provincial-towns': 'Oltre il corridoio della Senna, la cultura romana rimodellò le città provinciali. Juliobona (Lillebonne) ottenne un grande anfiteatro per migliaia di spettatori —le sue rovine sono ancora in piedi. Cosedia (Coutances) e Abrincae (Avranches) ricevettero propri monumenti romani e collegamenti stradali. Non erano copie di Roma: erano luoghi ibridi dove le tradizioni celtiche sopravvivevano sotto una patina romana. Le divinità locali si fondevano con quelle romane, le tecniche celtiche del metallo si mescolavano agli stili imperiali e le aristocrazie tribali si reinventavano come magistrati in toga.',
  'rg-arc-lugdunensis': 'La provincia della Lugdunensis Secunda abbracciava la maggior parte di ciò che sarebbe stata la Normandia. Governata da Rotomagus, era unita da calzate romane a Lutecia, ai porti della Manica e alla rete imperiale più ampia. L\'identità provinciale era definita dalla Senna: a monte, il cuore politico intorno a Parigi; a valle, il mare e le rotte verso la Britannia. L\'infrastruttura romana —strade, ponti, acquedotti— si sovrapponeva al paesaggio celtico, ma la geografia sottostante era la stessa: il corridoio fluviale, i margini costieri, il cuore agricolo. Ogni potere futuro avrebbe governato lo stesso terreno.',
  'rg-arc-saxon-shore': 'A metà del IV secolo, la costa della Manica era minacciata. Pirati sassoni e franchi assalivano le rive della Gallia e della Britannia con crescente audacia. Roma rispose con il Litus Saxonicum —la costa sassona—, una catena di forti costieri e torri di segnalazione per proteggere la traversata della Manica e le foce dei fiumi. L\'estuario della Senna ricevette fortificazioni; vedette scrutavano l\'orizzonte in cerca di vele ostili. Era un sistema difensivo nato dalla debolezza, non dalla forza: un impero che non poteva più impedire agli assalitori di raggiungere le sue coste, solo ritardarli. Lo schema era fissato per ciò che sarebbe venuto.',
  'rg-arc-crumbling-frontier': 'Agli inizi del V secolo, Roma non poteva più sostenere il nord della Gallia. Le legioni tornavano a difendere l\'Italia, le guarnizioni di frontiera restavano senza paga e il limes del Reno cedeva sotto la pressione di popoli germanici in migrazione. Le strade restavano, gli acquedotti portavano acqua e l\'anfiteatro di Juliobona era ancora in piedi, ma il potere che lo aveva costruito era scomparso. Rotomagus e Lutecia restarono alla deriva, con vescovi che occupavano il posto dei governatori. La Gallia romana finiva —ma infrastrutture, città e corridoi fluviali che aveva creato avrebbero sopravvissuto all\'imperio per altri mille anni.',
  'prg-arc-collapse': 'Agli inizi del V secolo, l\'impero romano non poteva più difendere il nord della Gallia. Le legioni si ritiravano per combattere guerre civili in Italia, le guarnizioni di frontiera restavano senza paga e bande germaniche attraversavano il Reno con crescente impunità. Rotomagus (Rouen) e Lutecia (Parigi) —città provinciali fiorenti— restarono tagliate dal sostegno imperiale. Le strade romane solcavano ancora il paesaggio, gli acquedotti eretti, ma il potere che li aveva edificati se n\'era andato. Il nord della Gallia entrò in un crepuscolo tra imperi.',
  'prg-arc-gallo-roman-cities': 'Benché l\'impero si ritirasse, le sue città non scomparvero. Rotomagus (Rouen) e Lutecia (Parigi) sopravvissero come isole di cultura romana in un mare di cambiamenti. I vescovi sostituirono i governatori come autorità civiche, mantenendo ordine, riscuotendo tributi e negoziando con i nuovi arrivati germanici. Il latino restò lingua del diritto e della liturgia. Le antiche trame urbane, le mura e le chiese diedero a quelle città una continuità che univa i mondi classico e medievale: una base che i Franchi avrebbero ereditato più che distrutto.',
  'prg-arc-frankish-settlement': 'I Franchi non erano un solo popolo ma una confederazione di tribù germaniche del basso Reno. Alcuni avevano servito come foederati —soldati alleati che difendevano la frontiera in cambio di terre. Crollato il controllo imperiale, i capi franchi penetrarono più a nord nella Gallia, stabilendosi sulle ricche terre coltivabili tra Reno, Somme e Senna. Non rasarono la civiltà gallo-romana: vi si sovrapposero, adottando usanze locali, sposando famiglie romane e rivendicando l\'autorità che le legioni avevano lasciato vacante.',
  'prg-arc-syagrius': 'Tra il nord franco e il sud visigoto sopravvisse un notevole reducto di autorità romana. Siagrio, figlio di un generale romano, governò uno stato residuo da Soissons —talvolta chiamato l\'ultimo enclave romano in Gallia. Il suo dominio si estendeva approssimativamente dalla Somme alla Loira e includeva Lutecia e Rotomagus. Per decenni mantenne amministrazione, coniazione e diritto romani in un mondo post-romano. Ma il suo regno era un\'isola e la marea franca saliva intorno.',
  'prg-arc-clovis-unification': 'Nel 486, il giovane re franco Clodoveo sconfisse Siagrio nella battaglia di Soissons e pose fine all\'ultima autorità romana nel nord della Gallia. Fu un momento decisivo: il bacino della Senna, con le sue città, strade e ricchezza agricola, passò da mani romane a mani franche. Clodoveo non distrusse ciò che conquistò —lo assorbì. Registri fiscali romani, reti ecclesiastiche e infrastruttura urbana sopravvissero sotto nuova gestione. Il regno franco che Clodoveo edificava sarebbe stato romano nella forma ma germanico nella forza.',
  'prg-arc-baptism': 'Verso il 496, Clodoveo si battezzò come cristiano cattolico —una mossa politica tanto quanto una conversione religiosa. Mentre altri re germanici erano ariani agli occhi di Roma, Clodoveo si alleò con i vescovi cattolici che ancora governavano le città della Gallia. La Chiesa offrì legittimità, alfabetizzazione e una rete amministrativa che raggiungeva ogni villa. In cambio, Clodoveo offrì la spada. Questa alleanza tra corona franca e Chiesa cattolica avrebbe definito il paesaggio politico dell\'Europa occidentale per mille anni.',
  'prg-arc-paris-capital': 'Clodoveo scelse Parigi come capitale —città romana rinata come sede reale franca. L\'antica isola fortificata di Lutecia, dove prima governavano prefetti romani, ospitava ora un re germanico che pregava in latino e parlava franco nel suo consiglio di guerra. La basilica che sarebbe stata Saint-Denis sorgeva alle porte, iniziando la sua lunga storia come pantheon dei re francesi. La posizione centrale di Parigi sulla Senna la faceva asse naturale di un regno che si estendeva dal Reno alla Loira.',
  'prg-arc-division': 'Quando Clodoveo morì nel 511, il suo regno fu diviso tra i quattro figli —non per debolezza, ma secondo l\'uso franco di trattare il regno come patrimonio familiare. La parte occidentale, centrata sul bacino della Senna con Parigi e Rouen come assi, prese il nome di Neustria. Il mondo post-romano era finito: il nord della Gallia era francamente franco, cattolico e medievale. Le strade romane erano ancora in uso, i vescovi governavano ancora le loro città, ma un nuovo ordine politico aveva messo radici —uno che avrebbe plasmato il corridoio della Senna per secoli.',
  'neu-arc-birth-of-neustria': 'Quando Clodoveo —primo re cristiano dei Franchi— morì nel 511, il suo regno fu spartito tra i figli secondo l\'uso franco. La parte occidentale, dalla Loira alla Manica e centrata sul bacino della Senna, ricevette il nome di Neustria —la «nuova terra occidentale». Parigi e Rouen ancoravano questo sottoregno, la cui identità avrebbe plasmato la geografia politica del nord della Gallia per oltre due secoli.',
  'neu-arc-paris-rouen-axis': 'La Senna univa le due grandi città della Neustria. Parigi, sulla sua isola fortificata, serviva da sede reale e crocevia; Rouen, a valle, controllava l\'accesso alla Manica e al mare. Tra le due correva un corridoio fluviale di pedaggi, grano e ordini reali. Questo asse Parigi–Rouen era la colonna del potere neustrico: chi dominava entrambe le città dominava il sottoregno. Lo stesso corridoio sarebbe stato più tardi l\'autostrada dell\'invasione vichinga.',
  'neu-arc-neustria-austrasia': 'Per generazioni, la Neustria e la sua rivale orientale Austrasia competettero per la supremazia nel mondo franco. Guerre civili, assassini e alleanze mutevoli definirono la politica merovingia. La forza della Neustria risiedeva nel ricco bacino agricolo della Senna e nell\'accesso al commercio della Manica, mentre l\'Austrasia si appoggiava al Reno. Questi conflitti fratricidi indebolirono entrambi i regni ma tennero indurite le aristocrazie guerriere —e le frontiere in costante movimento.',
  'neu-arc-merovingian-courts': 'Nel VII secolo, il potere reale nella Neustria era passato dai re merovingi ai loro majordomi —ministri capi che comandavano eserciti e controllavano il patronato. I re divennero figure cerimoniali, poi derisi come «re fannulloni». Questo svuotamento dell\'autorità reale significava che il destino della Neustria lo decidevano fazioni aristocratiche intorno a Parigi e all\'Île-de-France, non le teste incoronate.',
  'neu-arc-jumieges': 'Fondata verso il 654, l\'abbazia di Jumièges sorgeva in un ansa boscosa della Senna tra Rouen e il mare. Faceva parte di un\'ondata di fondazioni monastiche merovingie che trasformarono la bassa Senna in corridoio di preghiera, studio e —soprattutto— ricchezza. I monasteri ricevevano donazioni reali, riscuotevano pedaggi fluviali e attiravano pellegrini. Verso la fine del periodo neustrico, la valle della Senna ospitava alcune delle case religiose più ricche di tutta la Gallia —una concentrazione di tesori che sarebbe risultata irresistibile per futuri assalitori.',
  'neu-arc-nantes-breton-march': 'Al limite occidentale della Neustria, Nantes vigilava l\'estuario della Loira e la tesa frontiera con la penisola bretone. I bretoni —popoli di lingua celtica emigrati dalla Britannia— resistevano all\'autorità franca e assalivano verso est quando vacillava il potere neustrico. Nantes cambiò più volte mano, come guarnizione franca e come bersaglio dell\'ambizione bretone. Questa instabilità occidentale significava che la Neustria combatteva sempre su due fronti: contro l\'Austrasia a est e la Bretagna a ovest.',
  'neu-arc-tertry': 'Nel 687, il majordomo austrasiano Pipino di Herstal schiacciò l\'esercito neustrico nella battaglia di Tertry, presso Saint-Quentin. Fu un punto di svolta: la Neustria perse l\'indipendenza e cadde sotto dominazione austrasiana. Pipino e i suoi discendenti —i pipinidi, poi detti carolingi— governarono di fatto tutto il regno franco. I re merovingi restarono sul trono come figure, ma il potere reale era passato a est. I giorni della Neustria come regno rivale erano finiti.',
  'neu-arc-carolingian-dawn': 'Nel 751, Pipino il Breve —nipote del vincitore a Tertry— depose l\'ultimo re merovingio e fondò la dinastia carolingia con benedizione papale. La storia della Neustria come sottoregno franco indipendente era finita, ma la sua eredità perdurò: il corridoio della Senna che aveva reso arteria politica e monastica sarebbe diventato la via più ricca del nuovo impero carolingio. Abbazie, commercio fluviale, l\'asse Parigi–Rouen —tutto ciò che la Neustria aveva creato lo avrebbe ereditato Carlo Magno, e tutto ciò che Carlo Magno avesse lasciato indifeso lo avrebbero strappato i vichinghi.',
  'fc-arc-carolingian-rise': 'Nel 751, Pipino il Breve depose l\'ultimo re merovingio e fondò la dinastia carolingia con benedizione papale. La Neustria, a lungo sottoregno franco centrato sulla valle della Senna, fu integrata in un solo dominio reale. Parigi e Rouen —prima sedi di corti merovingie rivali— divennero città amministrate di un regno unificato. Quella concentrazione di potere avrebbe trasformato la bassa Senna da terra di frontiera politica in cuore economico dell\'Europa occidentale.',
  'fc-arc-charlemagne': 'Incoronato imperatore a Roma nell\'800, Carlo Magno costruì il più grande stato dell\'Europa occidentale dall\'antichità. Riorganizzò la Chiesa, unificò la coniazione e rafforzò le reti commerciali. Il corridoio della Senna divenne asse critico che collegava il cuore dell\'Île-de-France ai porti della Manica. Abbazie come Jumièges ricevettero carte reali e crebbero smisuratamente ricche, mentre l\'emporio di Quentovic gestiva il commercio transmanico con l\'Inghilterra anglosassone. Il successo stesso dell\'impero, tuttavia, creò uno schema di ricchezze indifese lungo i fiumi navigabili.',
  'fc-arc-seine-abbeys': 'La bassa Senna era fiancheggiata da alcuni dei monasteri più ricchi della cristianità. Jumièges, Saint-Wandrille e Fontenelle controllavano vaste terre, riscuotevano pedaggi e producevano manoscritti miniati. Rouen era il principale nodo urbano che collegava quella ricchezza monastica a Parigi a monte e alla Manica a valle. La protezione reale teneva al sicuro le abbazie —ma quella protezione dipendeva da una corona forte e unita. Il fiume che portava la loro ricchezza avrebbe presto portato i loro distruttori.',
  'fc-arc-quentovic-trade': 'Quentovic, presso l\'Étaples moderna sulla costa della Manica, era il principale emporio commerciale dell\'impero carolingio. Mercanti frisoni, anglosassoni e funzionari franchi vi si riunivano scambiando merci, argento e idee attraverso lo stretto. Carlo Magno regolò i pedaggi del porto e la sua zecca coniò monete che circolarono dalla Northumbria al Reno. La prosperità dell\'emporio dipendeva da mari in pace —condizione in procinto di finire.',
  'fc-arc-louis-pious': 'Luigi il Pio ereditò l\'impero di Carlo Magno nell\'814 e lo mantenne unito per una generazione —a un costo enorme. I suoi figli si ribellarono più volte, e le guerre civili che ne seguirono prosciugarono risorse militari dalla difesa di frontiera. Si assottigliarono le guarnizioni costiere, caddero le pattuglie fluviali e i conti locali restarono senza rinforzi. La stessa struttura che aveva fortificato l\'impero —comando centralizzato— divenne debolezza: quando vacillò il centro, il perimetro restò esposto.',
  'fc-arc-verdun': 'Luigi il Pio morì nell\'840 e l\'impero cadde subito in guerra civile. Il trattato di Verdun nell\'843 divise il regno carolingio in tre. La Francia occidentale —approssimativamente la Francia moderna— spettò a Carlo il Calvo, ma la sua autorità era fragile. La macchina militare che Carlo Magno aveva dispiegato per difendere coste e fiumi non rispondeva più a un solo comando. La Manica e i confini della Senna, prima corridoi interni di un vasto impero, erano ora frontiere esposte di uno stato indebolito.',
  'fc-arc-first-raids': 'Nel 841, l\'anno successivo alla morte di Luigi, drakkar nordici entrarono per la prima volta nell\'estuario della Senna. Gli assalitori colpirono Rouen quasi senza resistenza e saccheggiarono la grande abbazia di Jumièges. Non erano attacchi casuali: i mercanti scandinavi conoscevano da tempo la ricchezza che fluiva lungo la Senna, e le guerre civili carolingie segnalavano che le difese del fiume erano crollate. Le prime incursioni furono una ricognizione in forza —saggiando una frontiera che non poteva più reggere.',
  'fc-arc-storm-horizon': 'Nel 841, lo scenario era fissato. L\'impero carolingio che aveva arricchito i corridoi della Senna e della Loira —con il suo crollo— li aveva lasciati indifesi. Flotte nordiche tentarono già ogni grande foce da Nantes a Quentovic. Ciò che cominciò come incursioni stagionali sarebbe escalato in invasioni su vasta scala, accampamenti invernali e, infine, insediamento permanente. L\'era franca e carolingia non si chiuse con una successione tranquilla, ma con fumo sulle abbazie della bassa Senna —il primo atto dell\'età vichinga.',
  'va-arc-first-raids': 'Nel 841, drakkar nordici entrarono nell\'estuario della Senna e colsero di sorpresa le difese franche. Gli assalitori colpirono Rouen e saccheggiarono la grande abbazia di Jumièges. Non erano scorrerie isolate: la Senna era un\'autostrada verso una delle zone più ricche dell\'impero carolingio, fiancheggiata da monasteri opulenti e ville fluviali indifese. Le prime incursioni annunciarono uno schema che si sarebbe ripetuto per decenni.',
  'va-arc-seine-highway': 'Tra l\'840 e l\'880, flotte vichinghe usarono la Senna come corridoio d\'invasione ricorrente. Svernavano su isole fluviali, esigevano danegeld dalle ville franche e penetravano più a fondo ogni anno. Monasteri come Jumièges, Saint-Wandrille e Fontenelle furono saccheggiati e abbandonati. Il fiume che era stato il maggior bene del cuore carolingio —unendo Parigi al mare— divenne la sua vulnerabilità fatale.',
  'va-arc-wider-raids': 'La Senna non era l\'unico obiettivo. I vichinghi saccheggiarono Nantes nell\'843, usarono la Loira come via verso la Francia centrale e inviarono flotte lungo Reno e Mosa per devastare Dorestad, Utrecht e Colonia. Ogni grande fiume navigabile della Francia carolingia fu penetrato. L\'impero subiva assalti dall\'Atlantico ai Paesi Bassi, e la risposta militare decentrata dei Franchi —conti e vescovi che organizzavano difese improvvisate— non eguagliava velocità né coordinazione delle flotte nordiche.',
  'va-arc-siege-of-paris': 'Nel 885, una flotta nordica enorme —forse 300 navi e 30.000 uomini— risalì la Senna e assediò Parigi. Per oltre un anno, la guarnizione dell\'île de la Cité, al comando del conte Oddone e del vescovo Gozelone, resistette assalto su assalto. L\'imperatore franco Carlo il Grosso arrivò con l\'esercito —ma invece di combattere pagò i vichinghi perché si ritirassero e saccheggiassero la Borgogna. L\'umiliazione finì ciò che restava della credibilità militare carolingia in occidente.',
  'va-arc-danelaw-england': 'Il grande esercito pagano invase l\'Inghilterra nell\'865 e, in un decennio, buona parte dell\'est e del nord inglese passò sotto controllo scandinavo —il Danelaw. York divenne capitale come Jorvik, prospera città vichinga. Il Danelaw perdurò più di un secolo e creò un gruppo di coloni, guerrieri e mercanti angloscandinavi. Alcune di quelle famiglie del Danelaw avrebbero più tardi attraversato la Manica verso la Normandia dopo l\'911, aggiungendo un altro strato alla popolazione normanna.',
  'va-arc-norse-gaelic': 'Vichinghi norvegesi stabilirono una rete marittima per Scozia, Ebridi, Isola di Man e Irlanda dalla fine del VIII secolo. Dublino, fondata come longphort verso l\'841, fu centro del traffico di schiavi e ancora politica di un mondo norreno-gaelico dove si fondevano culture scandinava e celtica. Il jarldom delle Orcadi, sotto sovranità norvegese, controllava gli accessi settentrionali. Questa sfera noroccidentale avrebbe apportato coloni alla Normandia lungo la rotta del mare Celtico —una corrente migratoria distinta dal noto corridoio danese della Senna.',
  'va-arc-varangian-east': 'Mentre danesi e norvegesi assalivano verso ovest, i varanghi svedesi aprivano i sistemi fluviali dell\'est Europa. Da Birka e Hedeby, mercanti attraversavano il Baltico fino a Staraia Ladoga e Novgorod, seguivano il Dnepr a sud fino a Kiev e Costantinopoli, o il Volga a est fino ai mercati d\'argento islamici in Bulgar. Quelle rotte crearono la Rus\' di Kiev, rifornirono la guardia varanga bizantina e riversarono migliaia di dirham arabi di ritorno in Scandinavia. Il mondo vichingo non era solo atlantico —si estendeva dalla Vinland a Baghdad.',
  'va-arc-from-raids-to-treaty': 'Agli inizi del X secolo, decenni di assalti avevano trasformato la bassa Senna da cuore franco in frontiera contesa. Bande nordiche si stabilirono in modo semipermanente lungo il fiume. I re carolingi, indeboliti dalle guerre civili e incapaci di fermare le incursioni, scelsero di negoziare. Nel 911 Carlo il Semplice cedette il territorio della bassa Senna al capo vichingo Rollone in cambio di un cuscinetto difensivo contro nuove scorrerie nordiche. Il trattato di Saint-Clair-sur-Epte chiuse l\'età vichinga sulla Senna —e aprì l\'età della Normandia.',
  'no-arc-treaty': 'Nel 911, il re franco Carlo il Semplice cedette il territorio della bassa Senna al capo vichingo Rollone in cambio della promessa di difendere il fiume da nuovi assalti nordici. Il trattato di Saint-Clair-sur-Epte non fu un dono generoso ma il riconoscimento di un fatto compiuto: il potere franco aveva già perso il controllo della regione. Rollone e i suoi seguaci ricevettero Rouen e le terre intorno all\'estuario della Senna —il nucleo di ciò che sarebbe stata la Normandia.',
  'no-arc-danish-migration': 'I coloni che popolarono la Normandia precoce non erano un solo gruppo. Il nucleo politico intorno a Rouen si appoggiava fortemente a reti danesi —le stesse rotte del Mare del Nord che avevano alimentato il grande esercito pagano e il Danelaw. Famiglie angloscandinave del Danelaw attraversarono anche loro in Normandia come contadini e mercanti dopo l\'911, rafforzando la popolazione nordica del Bessin e delle terre basse interne. La colonia era scandinava, ma diversa fin dall\'inizio.',
  'no-arc-celtic-sea': 'Un secondo corridoio migratorio, meno noto, alimentò l\'ovest normanno. Vichinghi norvegesi stabiliti nelle Ebridi, nell\'Isola di Man e in Irlanda navigarono verso sud per il mare Celtico costeggiando la Cornovaglia fino alla Manica, raggiungendo la penisola del Cotentin e le isole del Canale. Ritrovamenti archeologici, toponimi del Cotentin con radici nordiche e pratiche funerarie distintive collegano l\'ovest normanno a questa rete del mare d\'Irlanda —promemoria che il ducato fu costruito con più correnti vichinghe, non solo col corridoio danese della Senna.',
  'no-arc-territorial-growth': 'La concessione originaria di Rollone copriva solo la bassa Senna intorno a Rouen. I suoi successori espansero il territorio con decisione verso ovest: il Bessin fu annesso nel 924, il Cotentin e l\'Avranchin nel 933. A metà del X secolo il ducato si estendeva dal fiume Epte fino alla costa atlantica del Cotentin —approssimativamente la forma della Normandia storica che avrebbe perdurato secoli. Ogni annessione incorporò nuove popolazioni sotto governo normanno e ampliò il confine ducale.',
  'no-arc-cultural-fusion': 'In due o tre generazioni, i coloni nordici avevano adottato la lingua francese, le consuetudini giuridiche franche e il cristianesimo. Rollone stesso si battezzò come parte dell\'accordo del 911. I monasteri saccheggiati nell\'età vichinga —Jumièges, Mont-Saint-Michel, Saint-Wandrille— furono restaurati e generosamente dotati dai nuovi duchi normanni. Ma perduravano l\'etica guerriera, la perizia marittima e il gusto per imprese militari ambiziose. Il risultato fu una cultura ibrida: di lingua francese, cristiana devota, ma con un filo scandinavo che distingueva i normanni dai vicini.',
  'no-arc-wider-viking-world': 'Mentre il ducato normanno si consolidava, il mondo vichingo più ampio era al suo apice. Le rotte commerciali scandinave si estendevano dalla Vinland a ovest fino a Costantinopoli e Baghdad a est. Il Danelaw in Inghilterra, i regni norreno-gaelici d\'Irlanda e Scozia, la Rus\' di Kiev e gli insediamenti islandesi e groenlandesi formavano una rete interconnessa. La Normandia era un nodo di quel sistema —i suoi coloni provenivano da quelle reti e la corte ducale primitiva mantenne legami con la Scandinavia molto tempo dopo aver adottato la cultura francese.',
  'no-arc-duchy-consolidated': 'A metà dell\'XI secolo, la Normandia era il principato più strettamente governato di tutta la Francia. Guglielmo (poi «il Conquistatore») ereditò un territorio con Chiesa riformata, rete di castelli che faceva rispettare l\'autorità ducale e aristocrazia feudale legata da lealtà personale. Innovazioni amministrative —giudici itineranti, registri dettagliati delle terre, zecca centralizzata a Rouen— diedero al duca un controllo che rivaleggiava con quello del re francese. Caen emerse come seconda capitale ducale, con le sue abbazie gemelle (Uomini e Donne) come manifestazione di pietà e ambizione normanne. Il ducato era pronto a proiettare il suo potere verso l\'esterno.',
  'no-arc-eve-of-conquest': 'Quando Edward il Confessore morì nel gennaio 1066, il duca Guglielmo rivendicò il trono inglese. In meno di 150 anni, una concessione a una banda guerriera vichinga sulla bassa Senna si era trasformata in una delle potenze più formidabili d\'Europa —di lingua francese, cristiana, amministrativamente avanzata e guidata da un duca la cui ambizione eguagliava le sue risorse. La flotta d\'invasione che si raccoglieva a Saint-Valéry-sur-Somme avrebbe portato non solo soldati ma un intero sistema di governo attraverso la Manica. Tutto ciò che seguì —la conquista d\'Inghilterra, i regni normanni di Sicilia, i principati crociati— nacque dal crogiolo di questo piccolo ducato sulla Senna.',
  'ne-arc-duchy-base': 'A metà dell\'XI secolo, il ducato di Normandia era l\'entità politica militarmente più formidabile del nord Francia. Un\'aristocrazia guerriera, costruzione di castelli su scala industriale e Chiesa riformata diedero al duca Guglielmo una base di potere senza pari tra i vicini. Quell\'energia concentrata stava per traboccare —attraverso la Manica, verso il Mediterraneo e fino alle porte di Gerusalemme.',
  'ne-arc-england': 'La vittoria di Guglielmo ad Hastings nel 1066 creò un regno anglonormanno su entrambe le sponde della Manica. L\'Inghilterra fu rimodellata: nuova aristocrazia, reti di castelli dalla Torre di Londra alle marche gallesi, il Domesday Book e l\'introduzione del francese normanno nel diritto e nella cultura. La conquista trasformò la Normandia in centro di un impero tramanic —ma legò anche il destino del ducato alla corona inglese.',
  'ne-arc-southern-italy': 'Avventurieri normanni —figli secondogeniti con poche prospettive in patria— arrivarono nel sud Italia come mercenari agli inizi dell\'XI secolo. In decenni, la famiglia Altavilla conquistò la Puglia, la Calabria e infine la Sicilia agli arabi. Ruggero II riunì quelle conquiste nel regno di Sicilia nel 1130, fondendo tradizioni normanna, bizantina, araba e latina in uno degli Stati più sofisticati dell\'Europa medievale.',
  'ne-arc-crusades': 'Signori normanni furono tra i leader più in vista della Prima Crociata (1096–1099). Boemondo di Taranto plasmò il principato d\'Antiochia; suo nipote Tancredi occupò la Galilea. Le tecniche militari normanne —carica di cavalleria pesante, costruzione di castelli, organizzazione feudale— servirono da modello agli Stati crociati in Levante. Un secolo dopo, Riccardo Cuor di Leone (di ascendenza normanna) conquistò Cipro in viaggio per la Terza Crociata.',
  'ne-arc-periphery': 'L\'espansione anglonormanna non si fermò ai vecchi confini d\'Inghilterra. I signori di marca spinsero verso il Galles dagli anni 1070, innalzando castelli a Chepstow, Pembroke e Caernarfon. Nel 1169, Strongbow attraversò il mare d\'Irlanda e prese Leinster, aprendo l\'Irlanda a secoli di signoria anglonormanna. Quelle campagne estesero strutture feudali normanne —castelli, mansioni rurali e carte di villaggio— fino al mondo celtico.',
  'ne-arc-byzantine-africa': 'L\'invasione di Roberto il Guiscardo nei Balcani (1081–1085) sfidò direttamente l\'impero bizantino —cavalleria normanna fin presso Costantinopoli da ovest. Nel frattempo, Ruggero II estese il potere siciliano nel Mediterraneo centrale e istituì brevemente un «regno d\'Africa» sulla costa tunisina (1135–1160). Le ambizioni normanne si estendevano dal mare d\'Irlanda al Bosforo.',
  'ne-arc-legacy': 'Nel XIII secolo il mondo normanno si dissolveva in identità maggiori —inglese, francese, siciliana. La Normandia stessa fu conquistata da Filippo Augusto nel 1204, tagliando il ducato tramanic. Pur così perdurarono eredità: la common law in Inghilterra, l\'architettura delle cattedrali da Durham a Monreale, la tenuta feudale della terra dall\'Irlanda al Levante, e una diaspora di cognomi, carte e rovine di castelli in tre continenti.',
};

